commands:
cat > /etc/nginx/conf.d/mechanic.conf << 'NGINX'
server {
    listen 443 ssl http2;
    server_name mechanic.codingeverest.com www.mechanic.codingeverest.com;

    ssl_certificate /etc/letsencrypt/live/mechanic.codingeverest.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/mechanic.codingeverest.com/privkey.pem;
    include /etc/letsencrypt/options-ssl-nginx.conf;
    ssl_dhparam /etc/letsencrypt/ssl-dhparams.pem;

    location / {
        proxy_pass http://localhost:3001;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_cache_bypass $http_upgrade;
    }
}

server {
    listen 80;
    server_name mechanic.codingeverest.com www.mechanic.codingeverest.com;
    return 301 https://mechanic.codingeverest.com$request_uri;
}
NGINX
rm -f /etc/nginx/sites-enabled/mechanic && nginx -t && systemctl reload nginx && echo NGINX_DONE
